{
  "name": "Low-Income Home Energy Assistance Program (LIHEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Gross monthly income at or below 150% of Federal Poverty Guidelines (FY26): 1: $2,608; 2: $3,525; 3: $4,441; 4: $5,358; 5: $6,275; 6: $7,191; 7: $8,108; 8: $9,025; 9: $9,942; 10: $10,859; 11+: Contact local OHEP office[1][4]",
    "asset_limits": "No asset limit[1]",
    "other_requirements": ["Household includes everyone at the address covered by the utility bill[1]", "SNAP or TCA recipients are categorically eligible without additional application or documentation[5]", "Proof of residency and SSN for all household members required[2][4]"]
  },
  "benefits": {
    "type": "financial",
    "value": "MEAP (heating): $25 minimum to $750 maximum; Crisis (winter): up to $600; EUSP (electric): separate grant once per July-June year; payments made directly to utility/fuel supplier[1][8]",
    "varies_by": "household_size|priority_tier|region"
  },
  "application": {
    "methods": ["Online: https://marylandbenefits.gov or https://mydhrbenefits.dhr.state.md.us[5][6]", "Phone: 1-800-332-6347[4][5][7]", "Mail: To local OHEP office[4][7]", "In-person: Local OHEP/energy office or home visits for seniors/disabled[5][7]"],
    "processing_time": "Not specified; apply early as funding limited[1]",
    "waitlist": "Funds may run out; some agencies stop accepting applications early[1]",
    "forms": ["DHS-FIA-9780-OHEP-Application for Energy Assistance[4]", "Declaration of Zero Income (if applicable)[7]", "Household Worksheet (if no income)[7]"],
    "documents": ["Photo ID (driver's license, state ID, passport, etc.; relaxed for age 62+/disabled: birth cert/Medicaid card sufficient)[2][4][7]", "Proof of residency (lease, rent receipt, utility bill)[4][7]", "SSN for all household members[2][4][7]", "Proof of gross income last 30 days[4][7]", "Recent utility bill or termination notice (if applicable)[4]", "For zero income: signed declaration[7]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available statewide[8]",
    "regional_variations": "Administered by local OHEP offices with potential differences in wait times, providers, and application deadlines due to funding[1][7]",
    "offices_or_providers": ["Local OHEP offices (contact via 1-800-332-6347 for specific locations)[4][7]"]
  },
  "official_source": "https://dhs.maryland.gov/office-of-home-energy-programs/[4][8]",
  "gotchas": ["No shut-off notice required to apply or qualify—apply early to prevent crisis[4][5][8]", "Cooling assistance not offered[1]", "Crisis only for emergencies like shutoff or broken furnace[1]", "Household counts all at address on utility bill, including roommates[1]", "EUSP once per program year only; MEAP separate from electric[8]", "Funding limited—apply ASAP as agencies may close early[1]", "USPP protection requires budget billing and consecutive payments[8]"],
  "data_shape_notes": "Administered via OHEP as MEAP (heating) and EUSP (electric); income-based statewide with local offices; categorical eligibility for SNAP/TCA; benefits vary by fuel type, size, crisis status; year-round but heating-focused with limited funds"
}

{
  "name": "State Health Insurance Assistance Program (SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all regardless of income, including low-income individuals seeking financial help with healthcare costs[1][4]",
    "asset_limits": "No asset limits or tests apply[1][4]",
    "other_requirements": ["Medicare beneficiaries (age 65+ or under 65 with disabilities)", "Individuals nearing Medicare eligibility", "Caregivers and family members assisting Medicare recipients"][1][2][4]
  },
  "benefits": {
    "type": "service",
    "value": "Free, unbiased, confidential one-on-one counseling and education on: Medicare basics (Parts A, B, C, D); Medicare Advantage and Medigap plans; prescription drug coverage (Part D); costs and financial assistance (MSPs, Medicaid, Extra Help); enrollment; claims/appeals; preventative benefits; billing issues; fraud; long-term care insurance; referrals. Also community presentations. No fixed dollar amounts or hours; available via phone, in-person[1][2][4]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: (410) 767-1100 to connect to local SHIP office[4]", "Phone: 1-800-243-3425[7]", "In-person or phone via local county offices (e.g., Carroll County: 410-386-3800, 125 Stoner Avenue, Westminster, MD 21157; Prince George's County office[1][2])", "No specific online application form; contact for counseling. Related forms for assistance programs: MSP application (9705-DHS-QMB-SLMB-MSP), Extra Help (SSA i1020), Maryland SPDAP[5]"],
    "processing_time": "Immediate counseling availability via phone or in-person; no formal processing as it's direct service[1][2][4]",
    "waitlist": null,
    "forms": ["No SHIP-specific application form; uses Medicare.gov or SSA links for enrollment/financial aid[5]"],
    "documents": ["No specific documents required for SHIP counseling itself; for related financial assistance (e.g., MSP, Extra Help): income proof, Medicare card, may vary by program[5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available in all 23 counties and Baltimore City[2][4]",
    "regional_variations": "Delivered through local trained staff and volunteer counselors in each county; contact central number for local office. Examples: Prince George's County office, Carroll County (410-386-3800), Anne Arundel County[1][2][5]",
    "offices_or_providers": ["Local offices in all 24 jurisdictions; call (410) 767-1100 for directory[4]"]
  },
  "official_source": "https://aging.maryland.gov/pages/state-health-insurance-program.aspx[4]",
  "gotchas": ["Not an insurance or financial aid program itself—provides counseling only, including help applying to aid programs like MSP/Extra Help; unbiased, no sales; available to non-Medicare eligible nearing eligibility or caregivers; Spanish support via (410) 767-1100[1][3][4]", "People miss that it's free counseling, not direct benefits; must contact local office for in-person[2][4]"],
  "data_shape_notes": "no income/asset test; counseling service only, not financial aid; county-based delivery with central access phone; open to pre-Medicare and caregivers"
}

{
  "name": "Meals on Wheels (via Senior Care Services and Area Agencies on Aging)",
  "eligibility": {
    "age": 60,
    "income_limits": "No fixed statewide dollar amounts specified; meals may be free, suggested donation, or sliding scale based on location, income, and need. Monthly income and expenses requested during intake to determine fees, but no documentation required[1][7].",
    "asset_limits": "No asset limits or exemptions mentioned in available sources.",
    "other_requirements": ["Homebound due to illness, physical/mental disability, or mobility challenges preventing shopping, meal preparation, or safe cooking[1][2][4][6]", "No caregiver available to assist with food shopping/preparation[4]", "Chronic health condition or disability may qualify those under 60 in some areas[2][4]"]
  },
  "benefits": {
    "type": "service",
    "value": "Home-delivered nutritious meals (typically 1 hot midday meal + 1 cold meal for later; 5 days/week Monday-Friday); special diets like diabetic/low carb, low sodium, mechanical soft; planned to meet RDAs for older adults. Varies by provider (e.g., 2 meals/day in Frederick County)[3][4]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Online form at Meals on Wheels of Central Maryland (mealsonwheelsmd.org/client-application/) for Central MD counties[7]", "Phone: 301-942-1111 for Montgomery County (mowwheaton.org)[2]", "Contact local Area Agency on Aging or provider directly; telephone intake common with needs assessment[1][7]", "Referral from doctor/social worker may be requested by some providers[1]"],
    "processing_time": "Allow 3 business days for start after application (Central MD)[7]",
    "waitlist": "Not specified; varies by region and provider demand (e.g., high need in Baltimore City, Essex, Dundalk, Glen Burnie)[3]",
    "forms": ["Client Application (online for Meals on Wheels of Central Maryland)[7]"],
    "documents": ["No documentation required, but prepare monthly income/expenses info, ID/address, dietary needs, health/mobility details for telephone intake[1][7]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "County-specific; must live in provider service area (e.g., Central MD: Anne Arundel, Baltimore City/County, Carroll, Harford, Howard; Frederick County; Montgomery; Charles County)[3][4][6][7]",
    "regional_variations": "Eligibility details, meals per day, special diets, fees, wait times, and providers differ by county/provider (e.g., 2 meals/day in Frederick vs. standard 1 hot+1 cold elsewhere; homebound definitions vary slightly)[2][4][6]",
    "offices_or_providers": ["Meals on Wheels of Central Maryland (mealsonwheelsmd.org, serves Central MD counties)[3][7]", "Montgomery: mowwheaton.org, 301-942-1111[2]", "Frederick County Division of Aging and Independence, 1440 Taney Ave, Frederick, MD 21702[4]", "Charles County (local AAoA)[6]"]
  },
  "official_source": "https://www.mealsonwheelsamerica.org/find-meals-and-services/ (national locator; contact Maryland AAoAs via aging.maryland.gov)",
  "gotchas": ["Must contact local provider/AAoA for exact eligibility/fees as no uniform statewide rules—varies significantly by county[1][4]", "Not automatically free; sliding scale or suggested donation based on income despite no strict limits[1][7]", "Primarily weekday delivery (Mon-Fri), no weekends standard[3][7]", "High demand areas like Baltimore City may have longer waits[3]", "Younger than 60 may qualify only with chronic disability in select programs[2][4]"],
  "data_shape_notes": "Highly decentralized by county/provider via local Area Agencies on Aging; no uniform income table or statewide asset test; contact local AAoA required for precise details"
}

{
  "name": "National Family Caregiver Support Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits specified in program guidelines[1][3][4]",
    "asset_limits": "No asset limits specified; no information on what counts or exemptions[1][3][4]",
    "other_requirements": [
      "Adult family members or other informal caregivers age 18 and older providing care to individuals 60 years of age and older[1][3][4]",
      "Adult family members or other informal caregivers age 18 and older providing care to individuals of any age with Alzheimer's disease and related disorders[1][3][4]",
      "Grandparents and other relatives (not parents) 55 years of age and older providing care to children under the age of 18[1][3][4]",
      "Grandparents and other relatives (not parents) 55 years of age and older providing care to adults age 18-59 with disabilities[1][3][4]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Five specific services: 1) Information to caregivers about available services; 2) Assistance to caregivers in gaining access to services; 3) Individual counseling, organization of support groups, and caregiver training; 4) Respite care; 5) Supplemental services on a limited basis. No specified dollar amounts or hours per week[1][3][4][7]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": [
      "Contact local Area Agency on Aging (AAA); administered by Maryland's local network of Area Agencies on Aging[1]",
      "No specific statewide phone, online URL, mail, or in-person details in sources; eligibility screenings and application help provided by local providers like Montgomery County HHS or MAC Inc[5][7]"
    ],
    "processing_time": "No specific timeline provided in sources",
    "waitlist": "No information on waitlists; may vary regionally but not specified",
    "forms": ["No specific form names or numbers identified"],
    "documents": ["No specific documents listed; prepare proof of caregiver relationship and care recipient details for screening[5]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None statewide; services via local Area Agencies on Aging[1]",
    "regional_variations": "Administered locally by Area Agencies on Aging, with potential differences in providers, availability, and wait times by county or region (e.g., Montgomery County, MAC Inc for specific areas); eligibility screenings vary[1][5][7]",
    "offices_or_providers": ["Local Area Agencies on Aging network; examples: Montgomery County HHS, MAC Inc[1][5][7]"]
  },
  "official_source": "https://aging.maryland.gov/pages/national-family-caregiver-support.aspx[1]",
  "gotchas": [
    "Must contact local Area Agency on Aging, not a centralized state application; no uniform process or forms[1]",
    "No income or asset tests, but services like supplemental and respite are limited availability[1][3][4]",
    "Eligibility focuses on caregiver types and care recipient categories, not financial need[1][4]",
    "Processing times, waitlists, and exact documents vary by local provider[5][7]"
  ],
  "data_shape_notes": "Administered through local Area Agencies on Aging with no statewide income/asset tests; services capped as 'limited basis' for some categories; regional provider variations require local contact[1][5][7]"
}

{
  "name": "MTA Senior Discount Program (Reduced Fare CharmCard®)",
  "eligibility": {
    "age": 65,
    "income_limits": "No income limits or asset limits apply. Eligibility is based solely on age or disability status, with no household size variations or financial tests.",
    "asset_limits": "Not applicable; no asset requirements.",
    "other_requirements": ["Valid government-issued photo ID showing date of birth (e.g., driver's license, state ID, passport).", "Alternatively: Medicare card paired with government-issued photo ID.", "MTA Senior Photo ID (no longer issued, but existing cards accepted)."]
  },
  "benefits": {
    "type": "financial",
    "value": "Reduced (typically half) fares on MTA Local Bus, Commuter Bus, Light Rail, Metro Subway, and MARC Train services. Exact reduced fare amounts available on MTA Fares page; payable via CharmPass app, cash, or compatible cards (note: physical CharmCards phased out as of March 1, 2026).",
    "varies_by": "fixed"
  },
  "application": {
    "methods": ["Online via CharmPass app: https://www.mta.maryland.gov/charmpass-reduced-fare-application (link eligibility with photo ID upload).", "In-person at MTA Reduced Fare Certification Office, 4201 Patterson Ave, 1st Floor, Baltimore, MD 21215 (Mon-Thu 8:30am-4:30pm).", "Phone: 410-767-3438 or 410-767-3441.", "Email: MTAReduceFareCertification@mta.maryland.gov."],
    "processing_time": "Immediate for in-person verification; app-based linking is instant upon approval.",
    "waitlist": null,
    "forms": ["No specific form name/number required; use CharmPass app for digital eligibility linking or show ID in-person."],
    "documents": ["Government-issued photo ID with date of birth.", "Medicare card (if applicable).", "Existing MTA Senior Photo ID or Disability ID (if applicable)."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available throughout Maryland on MTA services; primarily serves Baltimore region, Baltimore County, Anne Arundel County, but MARC extends statewide.",
    "regional_variations": "No variations in eligibility or benefits; uniform across MTA services. CharmPass app works statewide.",
    "offices_or_providers": ["MTA Reduced Fare Certification Office: 4201 Patterson Ave, 1st Floor, Baltimore, MD 21215.", "6 St. Paul St. Lobby Level, Baltimore, MD 21202 (alternative contact point)."]
  },
  "official_source": "https://www.mta.maryland.gov/senior-reduced-fare-program",
  "gotchas": ["Physical CharmCards are no longer accepted for fare payment as of March 1, 2026—must use CharmPass mobile app, cash with ID, or compatible digital cards.", "MTA Senior Photo IDs are no longer issued; apply for free Maryland MVA Photo ID instead.", "Must show valid ID every time to board at reduced fare; operators may request proof.", "Not compatible with all regional systems without additional verification (e.g., WMATA SmarTrip for cross-agency use).", "No free rides—only reduced fares."],
  "data_shape_notes": "no income test; ID-based only; transitioning from physical CharmCard to mobile CharmPass app; uniform eligibility statewide on MTA services"
}
